mapper.select:
SELECT t1.project_id,t1.labels,t2.a_n,t2.a_l,t2.a_s,t2.a_g from (SELECT project_id, GROUP_CONCAT(name ORDER BY id ASC) as labels FROM engine_label GROUP BY project_id )t1 INNER JOIN (SELECT id,a_n,a_l,a_s,a_g from engine_project Where 1=1
AND a_l = #{a_l}
AND a_s = #{a_s}
AND a_g = #{a_g}
)t2 on t1.project_id=t2.id
INNER JOIN (SELECT project_id FROM sys_user_project WHERE user_id = #{user_id}) t3 ON t1.project_id = t3.project_id
